contracts/PolicyRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./IPolicyRegistry.sol";
import "./PremiumPool.sol";

//This is the meat of the application. Please god work.
contract PolicyRegistry is
    AccessControl,
    ReentrancyGuard,
    IPolicyRegistry
{
    //Very helpful for assiging fixed roles
    bytes32 public constant ADMIN_ROLE =
        keccak256("ADMIN_ROLE");

    bytes32 public constant INSURER_ROLE =
        keccak256("INSURER_ROLE");

    IERC20 public immutable stablecoin;

    address public premiumPool;

    uint256 private _policyIdCounter;

    //Setting limitations of policies.
    mapping(uint256 => Policy) private _policies;
    mapping(address => uint256[]) private _policiesByInvestor;

    event PolicyCreated(
        uint256 indexed policyId,
        address indexed investor,
        uint256 coverageAmount,
        uint256 premiumAmount,
        string triggerType
    );

    event PremiumPoolSet(address indexed pool);

    //most important key events
    event PolicyPurchased(
        uint256 indexed policyId,
        address indexed investor
    );

    constructor(address stablecoinAddress) {
        //know the addresses
        stablecoin = IERC20(stablecoinAddress);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
        _grantRole(INSURER_ROLE, msg.sender);
    }

    function setPremiumPool(
        address pool
    ) external onlyRole(INSURER_ROLE) {
        require(pool != address(0), "invalid pool");

        premiumPool = pool;

        emit PremiumPoolSet(pool);
    }

    function createPolicy(
        //What really makes up a policy
        address investor,
        uint256 coverageAmount,
        uint256 premiumAmount,
        uint256 triggerThresholdBps,
        string calldata triggerType
    )
        external
        onlyRole(INSURER_ROLE)
        returns (uint256)
    {
        require(
            investor != address(0),
            "bad investor"
        );

        require(
            coverageAmount > 0,
            "bad coverage"
        );

        require(
            premiumAmount > 0,
            "bad premium"
        );

        require(
            triggerThresholdBps > 0,
            "bad threshold"
        );

        _policyIdCounter++;

        uint256 policyId = _policyIdCounter;

        _policies[policyId] = Policy({
            id: policyId,
            investor: investor,
            coverageAmount: coverageAmount,
            premiumAmount: premiumAmount,
            triggerThresholdBps: triggerThresholdBps,
            active: false,
            paidOut: false,
            triggerType: triggerType
        });

        emit PolicyCreated(
            policyId,
            investor,
            coverageAmount,
            premiumAmount,
            triggerType
        );

        return policyId;
    }

    function purchasePolicy(
        uint256 policyId
    ) external nonReentrant {

        Policy storage p = _policies[policyId];

        require(
            p.id != 0,
            "policy not found"
        );

        require(
            msg.sender == p.investor,
            "not investor"
        );

        require(
            !p.active,
            "already active"
        );

        require(
            premiumPool != address(0),
            "pool not set"
        );

        require(
            stablecoin.transferFrom(
                msg.sender,
                premiumPool,
                p.premiumAmount
            ),
            "premium transfer failed"
        );

        PremiumPool(premiumPool).recordPremium(
            p.premiumAmount
        );

        p.active = true;

        _policiesByInvestor[msg.sender].push(
            policyId
        );

        emit PolicyPurchased(
            policyId,
            msg.sender
        );
    }

    function markPaidOut(
        uint256 policyId
    ) external onlyRole(ADMIN_ROLE) {

        Policy storage p = _policies[policyId];

        require(
            p.id != 0,
            "policy not found"
        );

        require(
            p.active,
            "policy inactive"
        );

        require(
            !p.paidOut,
            "already paid"
        );

        p.paidOut = true;
    }

    function getPolicy(
        uint256 policyId
    )
        external
        view
        override
        returns (Policy memory)
    {
        require(
            _policies[policyId].id != 0,
            "policy not found"
        );

        return _policies[policyId];
    }

    function getPoliciesByInvestor(
        address investor
    )
        external
        view
        returns (uint256[] memory)
    {
        return _policiesByInvestor[investor];
    }

    function getPolicyCount()
        external
        view
        returns (uint256)
    {
        return _policyIdCounter;
    }
}

contracts/PremiumPool.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

//This is needed to allow investment by the insurers. This will be used as a bank account in this MVP version, that does allow payouts.
contract PremiumPool is AccessControl, ReentrancyGuard {
    bytes32 public constant ORACLE_ROLE = keccak256("ORACLE_ROLE");
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant REGISTRY_ROLE = keccak256("REGISTRY_ROLE"); // new

    IERC20 public immutable stablecoin;
    address public policyRegistry;

    uint256 public totalPremiums;
    uint256 public totalPayouts;

    event PoolLinked(address indexed policyRegistry);
    event PremiumRecorded(uint256 amount);
    event PayoutExecuted(address indexed investor, uint256 amount, uint256 indexed policyId, string triggerType);

    constructor(address stablecoinAddress) {
        stablecoin = IERC20(stablecoinAddress);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
    }

    function linkPolicyRegistry(address registry) external onlyRole(ADMIN_ROLE) {
        require(registry != address(0), "invalid registry");
        policyRegistry = registry;
        //Granting REGISTRY_ROLE in order for premiums to be granted
        _grantRole(REGISTRY_ROLE, registry);
        emit PoolLinked(registry);
    }

    //the registry contract will have this role. ONLY THEM
    function recordPremium(uint256 amount) external onlyRole(REGISTRY_ROLE) {
        require(amount > 0, "amount must be >0");
        totalPremiums += amount;
        emit PremiumRecorded(amount);
    }

    function executePayout(
        address investor,
        uint256 amount,
        uint256 policyId,
        string calldata triggerType
    ) external onlyRole(ORACLE_ROLE) nonReentrant {
        require(stablecoin.balanceOf(address(this)) >= amount, "insufficient pool");
        totalPayouts += amount;
        require(stablecoin.transfer(investor, amount), "payout transfer failed");
        emit PayoutExecuted(investor, amount, policyId, triggerType);
    }

    //Some viewer functions for when we are displaying hyper specifics to the frontend
    function getPoolBalance() public view returns (uint256) {
        return stablecoin.balanceOf(address(this));
    }

    function getAvailableLiquidity() external view returns (uint256) {
        return stablecoin.balanceOf(address(this));
    }

    function getTotalPremiums() external view returns (uint256) {
        return totalPremiums;
    }

    function getTotalPayouts() external view returns (uint256) {
        return totalPayouts;
    }

    function getReserveRatio() external view returns (uint256) {
        if (totalPremiums == 0) return 0;
        return (stablecoin.balanceOf(address(this)) * 100) / totalPremiums;
    }
}

contracts/TriggerOracle.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "./PremiumPool.sol";
import "./PolicyRegistry.sol";

contract TriggerOracle is AccessControl {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant ORACLE_ROLE = keccak256("ORACLE_ROLE");

    PolicyRegistry public registry;
    PremiumPool public pool;

    //This is a contract which is solely for the purpose of acting as a trigger mechanism
    event TriggerSubmitted(uint256 indexed policyId, string triggerType, int256 triggerValue);

    constructor(address registryAddress, address poolAddress) {
        registry = PolicyRegistry(registryAddress);
        pool = PremiumPool(poolAddress);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
        _grantRole(ORACLE_ROLE, msg.sender);
    }

    function submitTrigger(uint256 policyId, string calldata triggerType, int256 triggerValue) external onlyRole(ADMIN_ROLE) {
        IPolicyRegistry.Policy memory p = registry.getPolicy(policyId);
        require(p.active, "policy inactive");
        require(!p.paidOut, "already paid");

        emit TriggerSubmitted(policyId, triggerType, triggerValue);
    }
}

